using namespace adsk::core;
using namespace adsk::fusion;

Ptr ui;

extern "C" XI_EXPORT bool run(const char* context)
{
    Ptr app = Application::get();
    if (!app)
        return false;

    ui = app->userInterface();
    if (!ui)
        return false;

    Ptr docs = app->documents();
    if (!docs)
        return false;

    // Create a document.
    Ptr doc = docs->add(DocumentTypes::FusionDesignDocumentType);
    if (!doc)
        return false;

    Ptr design = app->activeProduct();
    if (!design)
        return false;

    // Get the root component of the active design
    Ptr rootComp = design->rootComponent();
    if (!rootComp)
        return false;

    // Create three sub components under root component
    Ptr occs = rootComp->occurrences();
    if (!occs)
        return false;

    Ptr transform = adsk::core::Matrix3D::create();
    if (!transform)
        return false;

    Ptr subOcc1 = occs->addNewComponent(transform);
    if (!subOcc1)
        return false;

    Ptr subComp1 = subOcc1->component();
    if (!subComp1)
        return false;

    Ptr subOcc2 = occs->addNewComponent(transform);
    if (!subOcc2)
        return false;

    Ptr subComp2 = subOcc2->component();
    if (!subComp2)
        return false;

    Ptr subOcc3 = occs->addNewComponent(transform);
    if (!subOcc3)
        return false;

    Ptr subComp3 = subOcc3->component();
    if (!subComp3)
        return false;

    // Create sketch 1 in sub component 1
    Ptr sketches1 = subComp1->sketches();
    if (!sketches1)
        return false;

    Ptr yzPlane = rootComp->yZConstructionPlane();
    if (!yzPlane)
        return false;

    Ptr sketch1 = sketches1->add(yzPlane);
    if (!sketch1)
        return false;

    // Get sketch curves
    Ptr sketchCurves = sketch1->sketchCurves();
    if (!sketchCurves)
        return false;

    // Get sketch lines
    Ptr sketchLines = sketchCurves->sketchLines();
    if (!sketchLines)
        return false;

    // Create sketch rectangle
    Ptr startPoint = Point3D::create(-8.0, 0, 0);

    Ptr endPoint = Point3D::create(8.0, 8.0, 0);
    sketchLines->addTwoPointRectangle(startPoint, endPoint);

    // Get the profile
    Ptr profs1 = sketch1->profiles();
    if (!profs1)
        return false;

    Ptr prof1 = profs1->item(0);

    // Create an extrusion input
    Ptr feats1 = subComp1->features();
    if (!feats1)
        return false;

    Ptr extrudes1 = feats1->extrudeFeatures();
    if (!extrudes1)
        return false;

    Ptr extInput1 = extrudes1->createInput(prof1, FeatureOperations::NewBodyFeatureOperation);

    // Define that the extent is a distance extent of 2 cm
    Ptr distance1 = ValueInput::createByReal(2.0);
    // Set the distance extent
    extInput1->setDistanceExtent(false, distance1);
    // Set the extrude type to be solid
    extInput1->isSolid(true);

    // Create the extrusion
    Ptr ext1 = extrudes1->add(extInput1);
    if (!ext1)
        return false;

    // Create construction plane
    Ptr planes = rootComp->constructionPlanes();
    if (!planes)
        return false;

    // Create construction plane input
    Ptr planeInput = planes->createInput();
    if (!planeInput)
        return false;

    // Add construction plane by offset
    Ptr offsetValue = ValueInput::createByReal(8.0);
    planeInput->setByOffset(rootComp->yZConstructionPlane(), offsetValue);
    Ptr plane = planes->add(planeInput);

    // Create sketch 2 in sub component 2
    Ptr sketches2 = subComp2->sketches();
    if (!sketches2)
        return false;

    Ptr sketch2 = sketches2->add(plane);
    if (!sketch2)
        return false;

    // Create an object collection for the points.
    Ptr points = ObjectCollection::create();
    if (!points)
        return false;

    // Define the points the spline with fit through.
    points->add(Point3D::create(0, 8, 0));
    points->add(Point3D::create(5, 6, 0));
    points->add(Point3D::create(-5, 5, 0));

    // Get sketch curves
    Ptr sketch2Curves = sketch2->sketchCurves();
    if (!sketch2Curves)
        return false;

    // Create the spline.
    Ptr splines = sketch2Curves->sketchFittedSplines();
    if (!splines)
        return false;

    Ptr spline = splines->add(points);
    if (!spline)
        return false;

    // Get sketch lines
    Ptr sketch2Lines = sketch2Curves->sketchLines();
    if (!sketch2Lines)
        return false;

    // Create sketch rectangle
    Ptr startPoint2 = Point3D::create(-4, 2, 0);

    Ptr endPoint2 = Point3D::create(3, 4, 0);
    sketch2Lines->addTwoPointRectangle(startPoint2, endPoint2);

    // Get the profile
    Ptr profs2 = sketch2->profiles();
    if (!profs2)
        return false;

    Ptr prof2 = profs2->item(0);

    // Create an extrusion input
    Ptr feats2 = subComp2->features();
    if (!feats2)
        return false;

    Ptr extrudes2 = feats2->extrudeFeatures();
    if (!extrudes2)
        return false;

    Ptr extInput2 = extrudes2->createInput(prof2, FeatureOperations::NewBodyFeatureOperation);

    // Create distance value input
    Ptr cm2 = adsk::core::ValueInput::createByString("2 cm");

    // Create taper angle value input
    Ptr deg10 = adsk::core::ValueInput::createByString("10 deg");

    // Create a distance extent definition
    Ptr extent_distance_2 = adsk::fusion::DistanceExtentDefinition::create(cm2);
        extInput2->setOneSideExtent(extent_distance_2, adsk::fusion::ExtentDirections::PositiveExtentDirection, deg10));

    // Set the extrude type to be solid
    extInput2->isSolid(true);

    // Create the extrusion
    Ptr ext2 = extrudes2->add(extInput2);
    if (!ext2)
        return false;

    // Get the body with the first extrude
    Ptr bodies = ext1->bodies();
    if (!bodies)
        return false;

    Ptr body = bodies->item(0);
    if (!body)
        return false;

    // faces
    std::vector> faceVec;
    for (Ptr face : body->faces())
    {
        faceVec.push_back(face);
    }

    // curves
    std::vector> curveVec;
    for (Ptr curve : sketch2Curves)
    {
        curveVec.push_back(curve);
    }

    Ptr sketch2Points = sketch2->sketchPoints();
    if (!sketch2Points)
        return false;

    for (Ptr point : sketch2Points)
    {
        curveVec.push_back(point);
    }

    // Get the body with the second extrude
    Ptr bodies2 = ext2->bodies();
    if (!bodies2)
        return false;

    Ptr body2 = bodies2->item(0);
    if (!body2)
        return false;

    for (Ptr edge : body2->edges())
    {
        curveVec.push_back(edge);
    }

    curveVec.push_back(rootComp->yConstructionAxis());
    curveVec.push_back(rootComp->originConstructionPoint());

    Ptr sketches3 = subComp3->sketches();
    if (!sketches3)
        return false;

    // Create a sketch in sub component 3
    Ptr skAlongVecProject = sketches3->add(yzPlane);
    if (!skAlongVecProject)
        return false;
    // sketch project to surface (along vector)
    std::vector> projectedEntities = skAlongVecProject->projectToSurface(
        faceVec, curveVec, AlongVectorSurfaceProjectType, rootComp->xConstructionAxis());

    // Create a sketch in sub component 3
    Ptr skClosestPtProject = sketches3->add(yzPlane);
    projectedEntities.clear();
    // sketch project to surface (closest point)
    projectedEntities = skClosestPtProject->projectToSurface(faceVec, curveVec, ClosestPointSurfaceProjectType);


    return true;
}
